class Solution:
    def twoOutOfThree(self, nums1, nums2, nums3):
        from collections import Counter
        cnt = Counter()
        for s in (set(nums1), set(nums2), set(nums3)):
            for v in s:
                cnt[v] += 1
        return [v for v, c in cnt.items() if c >= 2]

