var twoOutOfThree = function(nums1, nums2, nums3) {
    const sets = [new Set(nums1), new Set(nums2), new Set(nums3)];
    const cnt = new Map();
    for (const s of sets) {
        for (const v of s) cnt.set(v, (cnt.get(v) || 0) + 1);
    }
    const res = [];
    for (const [v, c] of cnt) if (c >= 2) res.push(v);
    return res;
};
